class Solution:
    def countSteppingNumbers(self, low, high):
        MOD = 10 ** 9 + 7

        def is_stepping(s):
            for i in range(len(s) - 1):
                if abs(int(s[i]) - int(s[i + 1])) != 1:
                    return False
            return True

        lo, hi = int(low), int(high)
        count = 0
        x = lo
        while x <= hi:
            if is_stepping(str(x)):
                count += 1
            x += 1
        return count % MOD

