class Solution:
    def countSteppingNumbers(self, low, high):
        MOD = 10 ** 9 + 7

        def count_up_to(num_str):
            digits = [int(ch) for ch in num_str]
            n = len(digits)
            from functools import lru_cache

            @lru_cache(maxsize=None)
            def dp(pos, prev, tight, started):
                if pos == n:
                    return 1 if started else 0
                limit = digits[pos] if tight else 9
                total = 0
                for d in range(0, limit + 1):
                    ntight = tight and d == limit
                    if not started:
                        if d == 0:
                            total += dp(pos + 1, 0, ntight, False)
                        else:
                            total += dp(pos + 1, d, ntight, True)
                    elif abs(d - prev) == 1:
                        total += dp(pos + 1, d, ntight, True)
                return total % MOD

            result = dp(0, 0, True, False)
            dp.cache_clear()
            return result % MOD

        def subtract_one(num_str):
            digits = list(num_str)
            i = len(digits) - 1
            while i >= 0 and digits[i] == '0':
                digits[i] = '9'
                i -= 1
            digits[i] = str(int(digits[i]) - 1)
            result = ''.join(digits).lstrip('0')
            return result if result else '0'

        low_minus_one = subtract_one(low)
        count_low = 0 if low_minus_one == '0' else count_up_to(low_minus_one)
        count_high = count_up_to(high)
        return (count_high - count_low) % MOD

