var countSteppingNumbers = function(low, high) {
    const MOD = 1000000007n;

    function countUpTo(numStr) {
        const digits = numStr.split('').map(Number);
        const n = digits.length;
        const memo = new Map();

        function dp(pos, prev, tight, started) {
            if (pos === n) return started ? 1n : 0n;
            const key = pos + ',' + prev + ',' + (tight ? 1 : 0) + ',' + (started ? 1 : 0);
            if (memo.has(key)) return memo.get(key);
            const limit = tight ? digits[pos] : 9;
            let total = 0n;
            for (let d = 0; d <= limit; d++) {
                const ntight = tight && d === limit;
                if (!started) {
                    if (d === 0) {
                        total += dp(pos + 1, 0, ntight, false);
                    } else {
                        total += dp(pos + 1, d, ntight, true);
                    }
                } else if (Math.abs(d - prev) === 1) {
                    total += dp(pos + 1, d, ntight, true);
                }
            }
            total %= MOD;
            memo.set(key, total);
            return total;
        }

        return dp(0, 0, true, false);
    }

    function subtractOne(numStr) {
        const digits = numStr.split('');
        let i = digits.length - 1;
        while (i >= 0 && digits[i] === '0') {
            digits[i] = '9';
            i--;
        }
        digits[i] = String(Number(digits[i]) - 1);
        let result = digits.join('').replace(/^0+/, '');
        return result === '' ? '0' : result;
    }

    const lowMinusOne = subtractOne(low);
    const countLow = lowMinusOne === '0' ? 0n : countUpTo(lowMinusOne);
    const countHigh = countUpTo(high);
    let ans = (countHigh - countLow) % MOD;
    if (ans < 0n) ans += MOD;
    return Number(ans);
};
